const predictions = $('Get Predictions').first().json;
const quant = $('Get Quant').first().json;
const price = $('Get Price').first().json;
const signals = $('Get Signals').first().json;

const dir = predictions.direction || 'N/A';
const conf = predictions.confidence ? Math.round(predictions.confidence * 100) : 'N/A';
const change = predictions.predicted_change_pct ? predictions.predicted_change_pct.toFixed(2) : 'N/A';
const btcPrice = price.price ? Number(price.price).toLocaleString('en-US') : 'N/A';
const change24h = price.change_24h_pct ? price.change_24h_pct.toFixed(2) : 'N/A';

const action = quant.action || signals.action || 'N/A';
const score = quant.composite_score ? Math.round(quant.composite_score) : 'N/A';
const entry = signals.entry ? '$' + Number(signals.entry).toLocaleString('en-US') : 'N/A';
const target = signals.target ? '$' + Number(signals.target).toLocaleString('en-US') : 'N/A';
const stopLoss = signals.stop_loss ? '$' + Number(signals.stop_loss).toLocaleString('en-US') : 'N/A';

const dirEmoji = dir === 'bullish' ? '🟢' : dir === 'bearish' ? '🔴' : '🟡';
const actionEmoji = action === 'BUY' ? '🟢' : action === 'SELL' ? '🔴' : '🟡';

const now = new Date().toLocaleString('en-US', { timeZone: 'UTC', hour: '2-digit', minute: '2-digit' });

const html = `${dirEmoji} <b>BTC Seer Signal</b> — ${now} UTC

💰 <b>Price:</b> $${btcPrice} (${change24h}% 24h)
📊 <b>Direction:</b> ${dir.toUpperCase()}
🎯 <b>Confidence:</b> ${conf}%
📈 <b>Expected move:</b> ${change}%

${actionEmoji} <b>Action:</b> ${action}
📏 <b>Quant Score:</b> ${score}/100

🎯 <b>Entry:</b> ${entry}
✅ <b>Target:</b> ${target}
🛑 <b>Stop Loss:</b> ${stopLoss}

<i>Not financial advice. DYOR.</i>`;

return [{ json: { message: html } }];
